const CONFIG_LEADS = {
    "D1": [ 
        { amp: 0.10, pos: 0.08, width: 0.03 }, 
        { amp: -0.05, pos: 0.18, width: 0.01 }, 
        { amp: 0.60, pos: 0.20, width: 0.01 }, 
        { amp: -0.25, pos: 0.22, width: 0.01 }, 
        { amp: 0.30, pos: 0.40, width: 0.06 }  
    ],
    "D2": [ 
        { amp: 0.15, pos: 0.08, width: 0.03 },
        { amp: -0.15, pos: 0.18, width: 0.01 },
        { amp: 1.00, pos: 0.20, width: 0.01 }, 
        { amp: -0.35, pos: 0.22, width: 0.01 }, 
        { amp: 0.35, pos: 0.40, width: 0.06 }
    ],
    "D3": [ 
        { amp: 0.09, pos: 0.08, width: 0.03 },
        { amp: -0.20, pos: 0.18, width: 0.01 },
        { amp: 0.80, pos: 0.20, width: 0.01 }, 
        { amp: -0.05, pos: 0.22, width: 0.02 }, 
        { amp: 0.09, pos: 0.40, width: 0.06 } 
    ]
};

const ondasECG = CONFIG_LEADS[lead] || CONFIG_LEADS["D2"];

const PATOLOGIAS = {
    "NORMAL": ondasECG,
    "ST_ELEV": [ 
        { amp: 0.15, pos: 0.08, width: 0.03 }, 
        { amp: -0.15, pos: 0.18, width: 0.01 }, 
        { amp: 1.00, pos: 0.20, width: 0.01 },
        { amp: 0.30, pos: 0.28, width: 0.06 }, 
