    ],
    "ST_DEPR": [ 
        { amp: 0.15, pos: 0.08, width: 0.03 }, 
        { amp: -0.15, pos: 0.18, width: 0.01 }, 
        { amp: 1.00, pos: 0.20, width: 0.01 },
        { amp: -0.15, pos: 0.22, width: 0.02 }, 
        { amp: -0.35, pos: 0.27, width: 0.04 },
        { amp: 0.35, pos: 0.40, width: 0.06 }
    ],
    "BLOCK_1": [ 
        { amp: 0.15, pos: 0.01, width: 0.03 }, 
        { amp: -0.15, pos: 0.28, width: 0.01 }, 
        { amp: 1.00, pos: 0.30, width: 0.01 }, 
        { amp: -0.35, pos: 0.32, width: 0.01 }, 
        { amp: 0.35, pos: 0.50, width: 0.06 }
    ],
    "PEA": [ 
        { amp: 0.05, pos: 0.08, width: 0.03 }, 
        { amp: -0.05, pos: 0.18, width: 0.01 }, 
        { amp: 1.00, pos: 0.20, width: 0.02 },
        { amp: 0.55, pos: 0.25, width: 0.02 }, 
        { amp: -0.15, pos: 0.27, width: 0.02 }, 
        { amp: -0.25, pos: 0.32, width: 0.04 }, 
        { amp: 0.05, pos: 0.40, width: 0.06 } 
    ]
};

let ondasECG_pat = PATOLOGIAS[patologia] || PATOLOGIAS["NORMAL"];

let factor_salud = (spo2 - 80) / 20; 
if (factor_salud < 0) factor_salud = 0;
if (factor_salud > 1) factor_salud = 1;

let muesca_amp = 0.4 * factor_salud; 

let ondasSpO2 = [
    { amp: 1.0, pos: 0.30, width: 0.10 }, 
    { amp: muesca_amp, pos: 0.60, width: 0.15 }  
];

let esParoCardiaco = (patologia === "ASYSTOLE" || patologia === "VFIB" || patologia === "PEA");

if (esParoCardiaco) {
    ondasSpO2 = []; 
    spo2 = 0; 
    pani_sistole = 0;
    pani_diastole = 0;

    if (patologia === "ASYSTOLE" || patologia === "VFIB") {
        bpm = 0;
        soundEnabled = false; 
    }
}

const RESOLUCION = 1000;
let tablaECG = [];
let tablaSpO2 = [];
let ondaFinal;
let valE;
let t;
let i;
let valS;
let ruido;

for (i = 0; i < RESOLUCION; i++) {
    t = i / RESOLUCION;

    valE = 0;
    if (patologia === "VFIB") {
        let onda1 = Math.sin(t * 22);        
        let onda2 = Math.cos(t * 37) * 0.8;  
        let onda3 = Math.sin(t * 54) * 0.5;  
        let onda4 = Math.cos(t * 89) * 0.3;  
        valE = onda1 + onda2 + onda3 + onda4;
        valE = valE * 0.4;
        valE += (Math.random() - 0.5) * 0.15;
    } else if (patologia === "ASYSTOLE") {
        valE = (Math.random() - 0.5) * 0.05;
    } else {
        if (patologia === "NORMAL") {
            ondaFinal = ondasECG;
        } else {
            ondaFinal = ondasECG_pat;
        }
        ondaFinal.forEach(o => {
            valE += o.amp * Math.exp( -Math.pow(t - o.pos, 2) / (2 * Math.pow(o.width, 2)));
        });
    }
    tablaECG.push(valE);

    valS = 0;
    ondasSpO2.forEach(o => {
        valS += o.amp * Math.exp( -Math.pow(t - o.pos, 2) / (2 * Math.pow(o.width, 2)) );
    });

    if (spo2 < 85 && !esParoCardiaco) {
        ruido = (Math.random() - 0.2) * ((85 - spo2) * 0.005);
        valS += ruido;
    }

    tablaSpO2.push(valS);
}

let pam = Math.round(pani_diastole + ((pani_sistole - pani_diastole) / 3));

msg.payload = {
    bpm: bpm,            
    bpm_limite_min: bpm_limit_min,
